import 'package:flutter/material.dart';

// Model
class User {
  final String id;
  final String name;
  final String email;

  User({
    required this.id,
    required this.name,
    required this.email,
  });

  factory User.fromJson(Map<String, dynamic> json) => User(
        id: json['id'],
        name: json['name'],
        email: json['email'],
      );
}

// State
sealed class AsyncValue<T> {
  const AsyncValue();
}

class AsyncLoading<T> extends AsyncValue<T> {
  const AsyncLoading();
}

class AsyncData<T> extends AsyncValue<T> {
  final T value;
  const AsyncData(this.value);
}

class AsyncError<T> extends AsyncValue<T> {
  final Object error;
  const AsyncError(this.error);
}

// Provider
final userProvider = StateNotifierProvider<UserNotifier, AsyncValue<User?>>((ref) {
  return UserNotifier();
});

class UserNotifier extends StateNotifier<AsyncValue<User?>> {
  UserNotifier() : super(const AsyncLoading());

  Future<void> fetchUser(String id) async {
    state = const AsyncLoading();
    try {
      await Future.delayed(const Duration(seconds: 1));
      state = AsyncData(User(id: id, name: 'Test User', email: 'test@example.com'));
    } catch (e) {
      state = AsyncError(e);
    }
  }

  void clearUser() {
    state = const AsyncData(null);
  }
}

// UI
class UserScreen extends ConsumerWidget {
  const UserScreen({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final asyncUser = ref.watch(userProvider);

    return switch (asyncUser) {
      AsyncLoading() => const Center(child: CircularProgressIndicator()),
      AsyncData(:final value) when value != null => Card(
          child: ListTile(
            title: Text(value.name),
            subtitle: Text(value.email),
          ),
        ),
      AsyncError(:final error) => Text('Error: $error'),
      _ => const Text('No user'),
    };
  }
}
