  static final GlobalKey<NavigatorState> navigatorKey = GlobalKey<NavigatorState>();

  static NavigatorState get navigator => navigatorKey.currentState!;

  static Future<T?> push<T>(Widget page) {
    return navigator.push<T>(
      MaterialPageRoute(builder: (_) => page),
    );
  }

  static Future<T?> pushReplacement<T>(Widget page) {
    return navigator.pushReplacement<T, T>(
      MaterialPageRoute(builder: (_) => page),
    );
  }

  static void pop<T>([T? result]) {
    navigator.pop<T>(result);
  }

  static Future<T?> pushNamed<T>(String route, {Object? arguments}) {
    return navigator.pushNamed<T>(route, arguments: arguments);
  }

  static void popUntil(bool Function(Route) predicate) {
    navigator.popUntil(predicate);
  }
